// template.ts
export interface TemplateVariable {
  name:     string;
  type:     "text" | "select" | "toggle" | "number" | "examples";
  options?: string[];        // for select and toggle
  default?: string;
}

export interface PromptTemplate {
  id:          string;
  name:        string;
  system:      string;      // template string with {{variables}}
  userTurn:    string;      // template string with {{variables}}
  variables:   TemplateVariable[];
  version:     number;
}

export function extractVariables(template: string): string[] {
  const matches = template.match(/\{\{(\w+)\}\}/g) ?? [];
  return [...new Set(matches.map(m => m.slice(2, -2)))];
}

export function compileTemplate(template: string, values: Record<string, string>): string {
  return template.replace(/\{\{(\w+)\}\}/g, (_, name) => values[name] ?? `{{${name}}}`);
}

// Usage
const template = "You are teaching {{audience}} about {{topic}} in a {{tone}} tone.";
const vars     = extractVariables(template);   // ["audience", "topic", "tone"]
const compiled = compileTemplate(template, {
  audience: "beginners",
  topic: "closures",
  tone: "casual",
});
// → "You are teaching beginners about closures in a casual tone."

// usePromptBuilder.ts
import { useState, useMemo, useCallback } from "react";

export function usePromptBuilder(template: PromptTemplate) {
  const [values, setValues] = useState<Record<string, string>>(
    Object.fromEntries(template.variables.map(v => [v.name, v.default ?? ""]))
  );

  const compiledSystem = useMemo(
    () => compileTemplate(template.system, values),
    [template.system, values]
  );
  const compiledUser = useMemo(
    () => compileTemplate(template.userTurn, values),
    [template.userTurn, values]
  );

  const estimatedTokens = useMemo(
    () => Math.ceil((compiledSystem.length + compiledUser.length) / 4),
    [compiledSystem, compiledUser]
  );

  const setValue = useCallback((name: string, value: string) => {
    setValues(prev => ({ ...prev, [name]: value }));
  }, []);

  return { values, setValue, compiledSystem, compiledUser, estimatedTokens };
}

// VariableControl.tsx
interface Props {
  variable: TemplateVariable;
  value:    string;
  onChange: (name: string, value: string) => void;
}

export function VariableControl({ variable, value, onChange }: Props) {
  const { name, type, options } = variable;

  return (
    <div className="mb-4">
      <label className="text-xs text-gray-400 font-mono">{`{{${name}}}`}</label>
      {type === "text" && (
        <input
          value={value}
          onChange={e => onChange(name, e.target.value)}
          className="mt-1 w-full rounded border bg-gray-900 px-2 py-1 text-sm"
        />
      )}
      {type === "select" && (
        <select
          value={value}
          onChange={e => onChange(name, e.target.value)}
          className="mt-1 w-full rounded border bg-gray-900 px-2 py-1 text-sm"
        >
          {options?.map(opt => <option key={opt}>{opt}</option>)}
        </select>
      )}
      {type === "toggle" && (
        <div className="mt-1 flex gap-2">
          {options?.map(opt => (
            <button
              key={opt}
              onClick={() => onChange(name, opt)}
              className={`rounded px-3 py-1 text-xs ${
                value === opt ? "bg-indigo-700 text-white" : "bg-gray-800 text-gray-400"
              }`}
            >
              {opt}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// PromptPreview.tsx
interface Props {
  compiledSystem: string;
  compiledUser:   string;
  estimatedTokens: number;
  maxTokens:       number;
}

export function PromptPreview({ compiledSystem, compiledUser, estimatedTokens, maxTokens }: Props) {
  const pct  = (estimatedTokens / maxTokens) * 100;
  const warn = estimatedTokens > maxTokens * 0.8;

  return (
    <div className="rounded-lg border border-gray-700 bg-gray-900 p-4 font-mono text-sm">
      <p className="text-xs text-gray-500 mb-1">System</p>
      <pre className="whitespace-pre-wrap text-gray-200 mb-4">{compiledSystem}</pre>
      <p className="text-xs text-gray-500 mb-1">Human</p>
      <pre className="whitespace-pre-wrap text-blue-300">{compiledUser}</pre>

      {/* Token meter */}
      <div className="mt-4 flex items-center gap-3">
        <div className="flex-1 bg-gray-800 rounded-full h-2">
          <div
            className={`h-2 rounded-full ${warn ? "bg-amber-400" : "bg-green-400"}`}
            style={{ width: `${Math.min(pct, 100)}%` }}
          />
        </div>
        <span className={`text-xs ${warn ? "text-amber-400" : "text-gray-400"}`}>
          ~{estimatedTokens} / {maxTokens} tokens
        </span>
      </div>
    </div>
  );
}

// TemplateDiff.tsx — compare two compiled prompts
import { diffWords } from "diff";

interface Props {
  oldText: string;
  newText: string;
}

export function TemplateDiff({ oldText, newText }: Props) {
  const parts = diffWords(oldText, newText);

  return (
    <pre className="whitespace-pre-wrap text-sm p-4 bg-gray-900 rounded border border-gray-700">
      {parts.map((part, i) => (
        <span
          key={i}
          className={
            part.added   ? "bg-green-900 text-green-300" :
            part.removed ? "bg-red-900   text-red-300 line-through" :
            "text-gray-300"
          }
        >
          {part.value}
        </span>
      ))}
    </pre>
  );
}

// types.ts
export interface Example {
  id:        string;
  userInput: string;
  assistant: string;
  enabled:   boolean;
}

// In the builder, enabled examples are prepended to the messages array
function buildMessages(
  compiledUser: string,
  examples:     Example[],
): Array<{ role: string; content: string }> {
  const messages: Array<{ role: string; content: string }> = [];

  for (const ex of examples.filter(e => e.enabled)) {
    messages.push({ role: "user",      content: ex.userInput });
    messages.push({ role: "assistant", content: ex.assistant });
  }
  messages.push({ role: "user", content: compiledUser });
  return messages;
}
